-- Tabela de histórico de mensagens (memória do agente)
CREATE TABLE IF NOT EXISTS n8n_historico_mensagens (
    id SERIAL PRIMARY KEY,
    session_id VARCHAR(40) NOT NULL,
    message JSONB NOT NULL,
    created_at TIMESTAMP WITHOUT TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP
);
CREATE INDEX IF NOT EXISTS idx_historico_session
    ON n8n_historico_mensagens(session_id);

-- Fila de mensagens (debounce)
CREATE TABLE IF NOT EXISTS n8n_fila_mensagens (
    id BIGSERIAL PRIMARY KEY,
    id_mensagem VARCHAR(40) NOT NULL,
    telefone VARCHAR(40) NOT NULL,
    mensagem TEXT NOT NULL,
    "timestamp" TIMESTAMP WITHOUT TIME ZONE NOT NULL
);
CREATE INDEX IF NOT EXISTS idx_fila_telefone
    ON n8n_fila_mensagens(telefone);

-- Status de atendimento (lock de concorrência)
CREATE TABLE IF NOT EXISTS n8n_status_atendimento (
    id SERIAL PRIMARY KEY,
    session_id VARCHAR(40) UNIQUE NOT NULL,
    lock_conversa BOOLEAN DEFAULT FALSE,
    updated_at TIMESTAMP WITHOUT TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP
);
CREATE INDEX IF NOT EXISTS idx_status_session
    ON n8n_status_atendimento(session_id);

